mapper.select:
SELECT student_id
FROM STUDENTS
WHERE student_id = #{studentId}

SELECT name, grade, class_name, student_number, total_point
FROM students
WHERE student_id = #{studentId}
  AND password = #{password}

SELECT COALESCE(
               SUM(
                       CASE
                           WHEN order_content = 'BUY' THEN amount
                           ELSE -amount
                           END
               ),
               0
       ) AS amount
FROM ORDERS
WHERE student_id = #{studentId}
  AND stock_no = #{stockNo}
  AND order_state = 'MATCHED'

SELECT COALESCE((SUM(order_point * amount) / SUM(amount)), 0) AS average
FROM ORDERS
WHERE student_id = #{studentId}
  AND stock_no = #{stockNo}
  AND order_state = 'MATCHED'
  AND order_content = 'BUY'

SELECT COALESCE(SUM(order_point * amount), 0) AS purchasePrice
FROM ORDERS
WHERE student_id = #{studentId}
  AND stock_no = #{stockNo}
  AND order_state = 'MATCHED'
  AND order_content = 'BUY'

SELECT cp.purchase_date AS history_date, '쿠폰' AS history_type, cp.name AS history_content, -cp.purchase_point AS point_change FROM COUPON_PURCHASE cp WHERE cp.student_id = #{studentId}
UNION ALL
SELECT gp.get_point_date AS history_date, '지급' AS history_type, gp.get_point_content AS history_content, gp.point AS point_change FROM GET_POINT gp WHERE gp.student_id = #{studentId}
UNION ALL
SELECT t.trade_date AS history_date, '매수' AS history_type, s.name AS history_content, -(o.order_point * o.amount) AS point_change FROM TRADE t INNER JOIN ORDERS o ON t.buy_order_no = o.order_no INNER JOIN STOCKS s ON o.stock_no = s.stock_no WHERE o.student_id = #{studentId}
UNION ALL
SELECT t.trade_date AS history_date, '매도' AS history_type, s.name AS history_content, (o.order_point * o.amount) AS point_change FROM TRADE t INNER JOIN ORDERS o ON t.sell_order_no = o.order_no INNER JOIN STOCKS s ON o.stock_no = s.stock_no WHERE o.student_id = #{studentId}
ORDER BY history_date DESC
